sql:
SELECT dashboard_name, layout, chart_settings 
FROM dashboard_configurations 
WHERE user_id = 1;

SELECT index_name
FROM stock_indices
WHERE description LIKE '%NASDAQ%';

SELECT users.username
FROM users
WHERE users.user_id IN (
    SELECT trade_orders.user_id
    FROM trade_orders
);

SELECT DISTINCT username
FROM users
WHERE role = 'trader';

SELECT COUNT(*) 
FROM trade_orders 
WHERE user_id = '0';

SELECT category, COUNT(*)
FROM financial_news
GROUP BY category;

SELECT COUNT(*)
FROM daily_price_data
WHERE volume > 10000000;

SELECT "trade_date", "close_price"
FROM "daily_price_data"
WHERE "close_price" > 100;

external_knowledge:
- "financial whales" refers to major stock indices;
- "whispering softly into the market's ear" metaphorically suggests having a quiet or low impact on the market, indicated by low trading volume;
- "ruffles in the trading volume" are used to represent the volume of shares traded, here specifically less than 100,000 shares.

